/**
 * @summary Get messages for a session
 */
export const getGetMessagesUrl = (
  sessionId: number,
  params?: GetMessagesParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/sessions/${sessionId}/messages?${stringifiedParams}`
    : `/api/sessions/${sessionId}/messages`;
};

export const getMessages = async (
  sessionId: number,
  params?: GetMessagesParams,
  options?: RequestInit,
): Promise<Message[]> => {
  return customFetch<Message[]>(getGetMessagesUrl(sessionId, params), {
    ...options,
    method: "GET",
  });
};

export const getGetMessagesQueryKey = (
  sessionId: number,
  params?: GetMessagesParams,
) => {
  return [
    `/api/sessions/${sessionId}/messages`,
    ...(params ? [params] : []),
  ] as const;
};

export const getGetMessagesQueryOptions = <
  TData = Awaited<ReturnType<typeof getMessages>>,
  TError = ErrorType<unknown>,
>(
  sessionId: number,
  params?: GetMessagesParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getMessages>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetMessagesQueryKey(sessionId, params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getMessages>>> = ({
    signal,
  }) => getMessages(sessionId, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!sessionId,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getMessages>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type GetMessagesQueryResult = NonNullable<
  Awaited<ReturnType<typeof getMessages>>
>;
export type GetMessagesQueryError = ErrorType<unknown>;

